import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, ActivatedRoute, RouterLink } from '@angular/router';
import { RestaurantPublicService, PublicRestaurant, PublicDish, PublicCategory, PublicMenu } from '../../../services/restaurant-public.service';
import { LucideAngularModule } from 'lucide-angular';
import { BreakpointObserver, Breakpoints } from '@angular/cdk/layout';
import { AuthService } from '../../../services/Base/auth.service';
import { combineLatest, map, Observable } from 'rxjs';

interface MenuCategory {
  id: string;
  name: string;
  description?: string;
  dishes: PublicDish[];
}

@Component({
  selector: 'app-menu-display',
  templateUrl: './menu-display.html',
  styleUrls: ['./menu-display.css'],
  imports: [CommonModule, FormsModule, RouterLink, LucideAngularModule]
})
export class MenuDisplay implements OnInit {
  private restaurantPublicService = inject(RestaurantPublicService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);
  private breakpointObserver = inject(BreakpointObserver);
  public authService = inject(AuthService);

  restaurant: PublicRestaurant | null = null;
  menus: PublicMenu[] = [];
  selectedMenu: PublicMenu | null = null;
  categories: MenuCategory[] = [];
  loading = true;
  searchQuery = '';
  selectedCategory: string | null = null;

  isMobile$ = this.breakpointObserver.observe([Breakpoints.Handset, Breakpoints.TabletPortrait])
    .pipe(map(result => result.matches));

  showToggle$: Observable<boolean> = combineLatest([
    this.isMobile$,
    this.authService.sidebarCollapsed$
  ]).pipe(
    map(([isMobile, collapsed]) => isMobile && collapsed)
  );

  async ngOnInit() {
    const restaurantId = this.route.snapshot.paramMap.get('id');
    if (restaurantId) {
      await this.loadMenuData(restaurantId);
    } else {
      this.router.navigate(['/customer/search']);
    }
  }

  async loadMenuData(restaurantId: string) {
    try {
      this.loading = true;

      // Carica ristorante, menu attivi e categorie in parallelo
      const [restaurant, menus, categories] = await Promise.all([
        this.restaurantPublicService.loadRestaurantById(restaurantId),
        this.restaurantPublicService.loadRestaurantMenus(restaurantId),
        this.restaurantPublicService.loadRestaurantCategories(restaurantId)
      ]);

      this.restaurant = restaurant;
      this.menus = menus;

      if (!menus.length) {
        this.categories = [];
        return;
      }

      // Seleziona il menu di default, oppure il primo attivo
      this.selectedMenu = menus.find(m => m.is_default) ?? menus[0];

      // Carica i piatti del menu selezionato
      await this.loadDishesForMenu(this.selectedMenu.id, categories);

    } catch (error) {
      console.error('Error loading menu data:', error);
    } finally {
      this.loading = false;
    }
  }

  async loadDishesForMenu(menuId: string, categories?: PublicCategory[]) {
    // Se non passiamo le categorie (es. cambio menu), le prendiamo da quelle già caricate
    const cats = categories ?? await this.restaurantPublicService
      .loadRestaurantCategories(this.restaurant!.id);

    const dishes = await this.restaurantPublicService.loadMenuDishes(menuId);
    this.groupDishesByCategory(dishes, cats);

    // Reset filtri al cambio menu
    this.searchQuery = '';
    this.selectedCategory = null;
  }

  async selectMenu(menu: PublicMenu) {
    if (this.selectedMenu?.id === menu.id) return;
    this.selectedMenu = menu;
    this.loading = true;
    await this.loadDishesForMenu(menu.id);
    this.loading = false;
  }

  // Invariato — riusa la logica esistente
  groupDishesByCategory(dishes: PublicDish[], categories: PublicCategory[]) {
    const categoryMap = new Map<string, MenuCategory>();

    categories.forEach(cat => {
      categoryMap.set(cat.id, {
        id: cat.id,
        name: cat.name,
        description: cat.description || '',
        dishes: []
      });
    });

    categoryMap.set('uncategorized', {
      id: 'uncategorized',
      name: 'Specialità',
      description: 'Le nostre specialità',
      dishes: []
    });

    dishes.forEach(dish => {
      if (dish.category_id && categoryMap.has(dish.category_id)) {
        categoryMap.get(dish.category_id)!.dishes.push(dish);
      } else if (dish.category_name && !categoryMap.has(dish.category_id || 'unknown')) {
        categoryMap.set(dish.category_id || 'unknown', {
          id: dish.category_id || 'unknown',
          name: dish.category_name,
          description: '',
          dishes: [dish]
        });
      } else {
        categoryMap.get('uncategorized')!.dishes.push(dish);
      }
    });

    this.categories = Array.from(categoryMap.values())
      .filter(cat => cat.dishes.length > 0)
      .sort((a, b) => {
        if (a.id === 'uncategorized') return 1;
        if (b.id === 'uncategorized') return -1;
        return a.name.localeCompare(b.name);
      });
  }

  get filteredCategories(): MenuCategory[] {
    if (!this.searchQuery && !this.selectedCategory) return this.categories;

    return this.categories.reduce<MenuCategory[]>((results, category) => {
      if (this.selectedCategory && category.id !== this.selectedCategory) return results;

      const filteredDishes = this.searchQuery
        ? category.dishes.filter(dish => {
            const query = this.searchQuery.toLowerCase();
            return dish.name.toLowerCase().includes(query) ||
              dish.description?.toLowerCase().includes(query) ||
              dish.category_name?.toLowerCase().includes(query);
          })
        : [...category.dishes];

      if (filteredDishes.length > 0) results.push({ ...category, dishes: filteredDishes });
      return results;
    }, []);
  }

  selectCategory(categoryId: string | null) {
    this.selectedCategory = categoryId === this.selectedCategory ? null : categoryId;
  }

  onSearchChange() {}

  addToCart(dish: PublicDish) {
    console.log('Aggiunto al carrello:', dish);
  }

  formatPrice(price: number): string {
    return `€${price.toFixed(2).replace('.', ',')}`;
  }

  onDishImageError(event: Event, dish: PublicDish) {
    (event.target as HTMLImageElement).style.display = 'none';
  }

  onLogoError(event: Event) {
    (event.target as HTMLImageElement).style.display = 'none';
  }
}